mapper.select:
select u.user_id, u.nick_name, u.user_name, u.email, u.avatar, u.phonenumber, u.sex, u.status, u.del_flag, u.login_ip, u.login_date, u.create_by, u.create_time, u.remark
from tb_user u
where u.del_flag = '0'

	AND u.user_id = #{userId}


	AND u.user_name like concat('%', #{userName}, '%')


	AND u.status = #{status}


	AND u.phonenumber like concat('%', #{phonenumber}, '%')


	AND date_format(u.create_time,'%Y%m%d') >= date_format(#{params.beginTime},'%Y%m%d')


	AND date_format(u.create_time,'%Y%m%d') <= date_format(#{params.endTime},'%Y%m%d')


${params.dataScope}

mapper.update:
update tb_user
nick_name = #{nickName}, email = #{email}, phonenumber = #{phonenumber}, sex = #{sex}, avatar = #{avatar}, password = #{password}, status = #{status}, login_ip = #{loginIp}, login_date = #{loginDate}, update_by = #{updateBy}, remark = #{remark}, update_time = sysdate()
where user_id = #{userId}
